import React, { useEffect, useRef, useState } from "react";

// Mock Gantt library simulation
const gantt = {
  config: {},
  init: (container) => {
    console.log("Gantt initialized");
  },
  clearAll: () => {
    console.log("Gantt cleared");
  },
  parse: (data) => {
    console.log("Gantt data parsed:", data);
  }
};

// Mock context
const useProjects = () => {
  const [projects, setProjects] = useState([
    { id: 1, text: "Task 1", start_date: "2025-09-22 00:00", duration: 1, progress: 0 },
    { id: 2, text: "Task 2", start_date: "2025-09-22 00:00", duration: 1, progress: 0 },
  ]);

  const addProject = (project) => {
    setProjects([...projects, project]);
  };

  return { projects, addProject };
};

const Timeline = () => {
  const ganttContainer = useRef(null);
  const { projects, addProject } = useProjects();
  const [newProjectText, setNewProjectText] = useState("");

  useEffect(() => {
    gantt.config.xml_date = "%Y-%m-%d %H:%i";
    gantt.config.readonly = false;
    gantt.config.drag_move = true;
    gantt.config.drag_resize = true;
    gantt.config.drag_links = true;
    gantt.config.auto_scheduling = true;
    gantt.config.show_errors = false;
    gantt.config.highlight_critical_path = true;

    gantt.init(ganttContainer.current);

    gantt.clearAll();
    gantt.parse({
      data: projects,
      links: [
        { id: 1, source: 1, target: 2, type: "0" },
        { id: 2, source: 2, target: 3, type: "0" },
        { id: 3, source: 3, target: 4, type: "0" },
        { id: 4, source: 4, target: 5, type: "0" },
      ],
    });
  }, [projects]);

  const handleCreateProject = () => {
    if (!newProjectText.trim()) return;
    const newProject = {
      id: Date.now(),
      text: newProjectText,
      start_date: "2025-12-10 00:00",
      duration: 10,
      progress: 0,
    };
    addProject(newProject);
    setNewProjectText("");
  };

  const containerStyle = {
    padding: "2rem",
    fontFamily: "Arial, sans-serif",
    background: "#D0F0F4",
    minHeight: "100vh",
  };

  const mainBoxStyle = {
    margin: "0 auto",
    maxWidth: "1200px",
    borderRadius: "12px",
    boxShadow: "0 4px 20px rgba(0,0,0,0.1)",
    overflow: "hidden",
    backgroundColor: "#fff",
  };

  const titleStyle = {
    textAlign: "center",
    marginBottom: "2rem",
    fontSize: "2rem",
    fontWeight: "bold",
    letterSpacing: "2px",
  };

  const headerStyle = {
    padding: "20px",
    background: "#8B5CF6",
    color: "#fff",
    fontSize: "20px",
    fontWeight: "600",
    display: "flex",
    alignItems: "center",
    justifyContent: "center",
    gap: "10px",
  };

  const inputSectionStyle = {
    padding: "20px",
    display: "flex",
    gap: "10px",
    backgroundColor: "#f8f9fa",
  };

  const inputStyle = {
    flex: 1,
    padding: "12px",
    fontSize: "16px",
    border: "1px solid #ddd",
    borderRadius: "4px",
  };

  const buttonStyle = {
    padding: "12px 24px",
    fontSize: "16px",
    backgroundColor: "#3B82F6",
    color: "#fff",
    border: "none",
    borderRadius: "4px",
    cursor: "pointer",
    fontWeight: "600",
  };

  const ganttStyle = {
    height: "600px",
    width: "100%",
    backgroundColor: "#fff",
  };

  return (
    <div style={containerStyle}>
      <div style={titleStyle}>FLOW TRACK</div>

      <div style={mainBoxStyle}>
        <div style={headerStyle}>
          <svg width="24" height="24" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2">
            <rect x="3" y="4" width="18" height="18" rx="2" ry="2"></rect>
            <line x1="16" y1="2" x2="16" y2="6"></line>
            <line x1="8" y1="2" x2="8" y2="6"></line>
            <line x1="3" y1="10" x2="21" y2="10"></line>
          </svg>
          Project Timeline
        </div>

        <div style={inputSectionStyle}>
          <input
            type="text"
            value={newProjectText}
            onChange={(e) => setNewProjectText(e.target.value)}
            placeholder="New Project Name"
            style={inputStyle}
          />
          <button onClick={handleCreateProject} style={buttonStyle}>
            Add Project
          </button>
        </div>

        <div ref={ganttContainer} style={ganttStyle}>
          {/* Gantt Chart Mockup */}
          <div style={{ padding: "20px" }}>
            <table style={{ width: "100%", borderCollapse: "collapse" }}>
              <thead>
                <tr style={{ backgroundColor: "#f8f9fa", borderBottom: "2px solid #ddd" }}>
                  <th style={{ padding: "12px", textAlign: "left", width: "150px", border: "1px solid #ddd" }}>Task name</th>
                  <th style={{ padding: "12px", textAlign: "left", width: "120px", border: "1px solid #ddd" }}>Start time</th>
                  <th style={{ padding: "12px", textAlign: "left", width: "100px", border: "1px solid #ddd" }}>Duration</th>
                  <th style={{ padding: "12px", textAlign: "center", width: "50px", border: "1px solid #ddd" }}>+</th>
                  <th colSpan="2" style={{ padding: "12px", textAlign: "center", border: "1px solid #ddd" }}>September 2025</th>
                  <th colSpan="2" style={{ padding: "12px", textAlign: "center", border: "1px solid #ddd" }}>October 2025</th>
                </tr>
                <tr style={{ backgroundColor: "#f8f9fa", fontSize: "12px" }}>
                  <th style={{ border: "1px solid #ddd" }}></th>
                  <th style={{ border: "1px solid #ddd" }}></th>
                  <th style={{ border: "1px solid #ddd" }}></th>
                  <th style={{ border: "1px solid #ddd" }}></th>
                  <th style={{ padding: "8px", textAlign: "center", border: "1px solid #ddd" }}>28 Mon</th>
                  <th style={{ padding: "8px", textAlign: "center", border: "1px solid #ddd" }}>30 Tue</th>
                  <th style={{ padding: "8px", textAlign: "center", border: "1px solid #ddd" }}>01 Wed</th>
                  <th style={{ padding: "8px", textAlign: "center", border: "1px solid #ddd" }}>02 Thu</th>
                </tr>
              </thead>
              <tbody>
                {projects.map((project, index) => (
                  <tr key={project.id} style={{ borderBottom: "1px solid #ddd" }}>
                    <td style={{ padding: "12px", border: "1px solid #ddd" }}>
                      <button style={{ 
                        padding: "6px 16px", 
                        borderRadius: "16px", 
                        border: "1px solid #ddd",
                        backgroundColor: "#fff",
                        cursor: "pointer"
                      }}>
                        {project.text}
                      </button>
                    </td>
                    <td style={{ padding: "12px", border: "1px solid #ddd" }}>{project.start_date.split(" ")[0]}</td>
                    <td style={{ padding: "12px", border: "1px solid #ddd" }}>{project.duration}</td>
                    <td style={{ padding: "12px", textAlign: "center", border: "1px solid #ddd" }}>+</td>
                    <td colSpan={index === 0 ? "2" : "4"} style={{ padding: "12px", border: "1px solid #ddd" }}>
                      <div style={{
                        height: "30px",
                        backgroundColor: "#7DD3C0",
                        borderRadius: "4px",
                        width: index === 0 ? "100%" : "100%"
                      }}></div>
                    </td>
                    {index === 0 && (
                      <>
                        <td style={{ border: "1px solid #ddd" }}></td>
                        <td style={{ border: "1px solid #ddd" }}></td>
                      </>
                    )}
                  </tr>
                ))}
              </tbody>
            </table>
          </div>
        </div>
      </div>
    </div>
  );
};

export default Timeline;
